SELECT COUNT(*) FILTER (WHERE "isCancelled" = false) AS active_events, COUNT(*) FILTER (WHERE "isCancelled" = true) AS cancelled_events, COUNT(*) FILTER (WHERE "isCancelled" = false AND "externalSource" = 'perplexity') AS active_perplexity, COUNT(*) FILTER (WHERE "isCancelled" = false AND "externalSource" = 'ticketmaster') AS active_ticketmaster, COUNT(*) FILTER (WHERE "isCancelled" = false AND "externalSource" = 'skiddle') AS active_skiddle FROM "Event" WHERE "startsAt" >= NOW() - INTERVAL '7 days';